import React, { useState, useContext } from 'react';
import { Modal, Button } from 'react-bootstrap'; // Using Bootstrap for Modal

// Replace with your actual Cart Context implementation
const CartContext = React.createContext();

const ProductDetailsPopup = (props) => {
  const [show, setShow] = useState(false);
  const [selectedSize, setSelectedSize] = useState('');
  const [selectedColor, setSelectedColor] = useState('');

  const handleClose = () => setShow(false);
  const handleShow = () => setShow(true);

  const cartContext = useContext(CartContext); // Accessing Cart Context

  const handleAddToCart = () => {
    // Check for size and color selection before adding to cart
    if (!selectedSize || !selectedColor) {
      alert('Please select a size and color before adding to cart.');
      return;
    }

    // Add product to cart with selected size and color
    cartContext.addItem({
      ...props.product,
      size: selectedSize,
      color: selectedColor,
    });
    handleClose(); // Close the popup after adding to cart
  };

  return (
    <>
      <Button variant="primary" size="sm" onClick={handleShow}>
        Ver detalhes (View Details)
      </Button>

      <Modal show={show} onHide={handleClose}>
        <Modal.Header closeButton>
          <Modal.Title>{props.product.name}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <img src={props.product.image} alt={props.product.name} />
          <p className="text-gray-600">{props.product.description}</p>
          <p className="font-bold text-black">R$ {props.product.price.toFixed(2)}</p>
          <div className="mb-2">
            <label htmlFor="size">Tamanho (Size):</label>
            <select
              id="size"
              value={selectedSize}
              onChange={(e) => setSelectedSize(e.target.value)}
            >
              <option value="">Selecione (Select)</option>
              <option value="P">P</option>
              <option value="M">M</option>
              <option value="G">G</option>
            </select>
          </div>
          <div className="mb-2">
            <label htmlFor="color">Cor (Color):</label>
            <select
              id="color"
              value={selectedColor}
              onChange={(e) => setSelectedColor(e.target.value)}
            >
              <option value="">Selecione (Select)</option>
              <option value="preto">Preto (Black)</option>
              <option value="branco">Branco (White)</option>
              <option value="azul">Azul (Blue)</option>
            </select>
          </div>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={handleClose}>
            Fechar (Close)
          </Button>
          <Button variant="primary" disabled={!selectedSize || !selectedColor} onClick={handleAddToCart}>
            Adicionar ao Carrinho (Add to Cart)
          </Button>
        </Modal.Footer>
      </Modal>
    </>
  );
};

export default ProductDetailsPopup;
